I2C Read Register API <pre><code>drv_status_t i2c_read_reg(uint8_t dev_addr, uint8_t reg,
                           uint8_t *data, uint8_t len) {
    // Write register address
    if (!i2c_start(dev_addr, false)) return DRV_ERR_TIMEOUT;
    if (!i2c_write_byte(reg))        return DRV_ERR_NACK;

    // Read data
    if (!i2c_start(dev_addr, true))  return DRV_ERR_TIMEOUT;
    for (uint8_t i = 0; i &lt; len; i++) {
        bool ack = (i &lt; len - 1);    // NACK last byte
        if (!i2c_read_byte(&amp;data[i], ack)) return DRV_ERR_TIMEOUT;
    }
    i2c_stop();
    return DRV_OK;
}
</code></pre>

Polling Transfer <pre><code>uint8_t spi_transfer_byte(SPI_TypeDef *spi, uint8_t tx) {
    while (!(spi-&gt;SR &amp; SPI_SR_TXE));   // wait TX empty
    spi-&gt;DR = tx;
    while (!(spi-&gt;SR &amp; SPI_SR_RXNE));  // wait RX not empty
    return spi-&gt;DR;
}

void spi_transfer_buf(SPI_TypeDef *spi,
                       const uint8_t *tx, uint8_t *rx, uint16_t len) {
    for (uint16_t i = 0; i &lt; len; i++) {
        rx[i] = spi_transfer_byte(spi, tx ? tx[i] : 0xFF);
    }
}
</code></pre>

Ring Buffer Implementation <pre><code>typedef struct {
    uint8_t  buf[UART_BUF_SIZE];
    uint32_t head;
    uint32_t tail;
} ring_buf_t;

static bool rb_push(ring_buf_t *rb, uint8_t byte) {
    uint32_t next = (rb-&gt;head + 1) % UART_BUF_SIZE;
    if (next == rb-&gt;tail) return false;  // full
    rb-&gt;buf[rb-&gt;head] = byte;
    rb-&gt;head = next;
    return true;
}

static bool rb_pop(ring_buf_t *rb, uint8_t *out) {
    if (rb-&gt;head == rb-&gt;tail) return false;  // empty
    *out = rb-&gt;buf[rb-&gt;tail];
    rb-&gt;tail = (rb-&gt;tail + 1) % UART_BUF_SIZE;
    return true;
}
</code></pre>

Minimal Linker Script <pre><code>/* STM32F103C8 - 64K Flash, 20K RAM */
MEMORY {
    FLASH (rx)  : ORIGIN = 0x08000000, LENGTH = 64K
    RAM   (rwx) : ORIGIN = 0x20000000, LENGTH = 20K
}

ENTRY(Reset_Handler)

SECTIONS {
    .text : {
        *(.isr_vector)   /* Vector table first */
        *(.text*)         /* Code */
        *(.rodata*)       /* Read-only data */
    } &gt; FLASH

    /* .data load address in FLASH, runtime address in RAM */
    _sidata = LOADADDR(.data);
    .data : {
        _sdata = .;
        *(.data*)
        _edata = .;
    } &gt; RAM AT &gt; FLASH

    .bss : {
        _sbss = .;
        *(.bss*)
        *(COMMON)
        _ebss = .;
    } &gt; RAM

    /* Stack at top of RAM */
    _estack = ORIGIN(RAM) + LENGTH(RAM);
}
</code></pre>

