PWM Setup (STM32) <pre><code>void pwm_init(void) {
    RCC-&gt;APB1ENR |= RCC_APB1ENR_TIM3EN;
    RCC-&gt;APB2ENR |= RCC_APB2ENR_IOPAEN;

    // PA6 = TIM3_CH1 alternate function
    GPIOA-&gt;CRL = (GPIOA-&gt;CRL &amp; ~(0xFu&lt;&lt;24)) | (0xBu&lt;&lt;24);

    TIM3-&gt;PSC = 72 - 1;     // 1MHz timer clock
    TIM3-&gt;ARR = 1000 - 1;   // 1kHz PWM frequency
    TIM3-&gt;CCR1 = 500;        // 50% duty cycle

    // PWM mode 1: output high while CNT &lt; CCR1
    TIM3-&gt;CCMR1 = (6u &lt;&lt; 4) | TIM_CCMR1_OC1PE;
    TIM3-&gt;CCER  |= TIM_CCER_CC1E;
    TIM3-&gt;CR1   |= TIM_CR1_ARPE | TIM_CR1_CEN;
}

// Change duty cycle (0-1000 = 0-100%)
void pwm_set_duty(uint16_t duty) {
    TIM3-&gt;CCR1 = duty;
}
</code></pre>

STM32 SPI Init + TransferCS Control Pattern <pre><code>void spi_init(void) {
    // Enable clocks
    RCC-&gt;APB2ENR |= RCC_APB2ENR_SPI1EN | RCC_APB2ENR_IOPAEN;

    // PA5=SCK, PA6=MISO, PA7=MOSI as AF; PA4=CS as output
    GPIOA-&gt;CRL = (GPIOA-&gt;CRL &amp; ~0xFFFF0000u) | 0xB4B30000u;

    SPI1-&gt;CR1 = SPI_CR1_MSTR      // master
              | SPI_CR1_SSM       // software slave management
              | SPI_CR1_SSI       // internal SS high
              | (2u &lt;&lt; 3)         // PCLK/8 baud
              | SPI_CR1_SPE;      // enable
}

uint8_t spi_transfer(uint8_t tx) {
    while (!(SPI1-&gt;SR &amp; SPI_SR_TXE));  // wait TX empty
    SPI1-&gt;DR = tx;
    while (!(SPI1-&gt;SR &amp; SPI_SR_RXNE)); // wait RX not empty
    return SPI1-&gt;DR;
}
</code></pre> <pre><code>#define CS_LOW()   GPIOA-&gt;BSRR = (1u &lt;&lt; (4+16))  // reset PA4
#define CS_HIGH()  GPIOA-&gt;BSRR = (1u &lt;&lt; 4)        // set PA4

void spi_read_register(uint8_t reg, uint8_t *data, uint16_t len) {
    CS_LOW();
    spi_transfer(reg | 0x80u);  // read command (device-specific)
    for (uint16_t i = 0; i &lt; len; i++) data[i] = spi_transfer(0xFF);
    CS_HIGH();
}
</code></pre>

Periodic Interrupt (1kHz) <pre><code>void timer_init_1khz(void) {
    RCC-&gt;APB1ENR |= RCC_APB1ENR_TIM2EN;

    // 72MHz / (72-1+1) / (1000-1+1) = 1kHz overflow
    TIM2-&gt;PSC = 72 - 1;     // prescaler: 72MHz → 1MHz
    TIM2-&gt;ARR = 1000 - 1;   // auto-reload: 1MHz / 1000 = 1kHz
    TIM2-&gt;DIER |= TIM_DIER_UIE;  // update interrupt enable
    TIM2-&gt;CR1  |= TIM_CR1_CEN;   // start counter

    NVIC_EnableIRQ(TIM2_IRQn);
    NVIC_SetPriority(TIM2_IRQn, 1);
}

void TIM2_IRQHandler(void) {
    if (TIM2-&gt;SR &amp; TIM_SR_UIF) {
        TIM2-&gt;SR &amp;= ~TIM_SR_UIF;  // clear flag
